parameters.text:
=다음 MR을 검토하고, 코드 리뷰 코멘트를 작성해주세요.

# MR 정보:
{{ 
  $json.title + "\n\n" +
  $json.description + "\n\n대상 브랜치: " +
  $json.source_branch + " → " +
  $json.target_branch
}}

# 변경된 파일:
{{ 
  $json.changes.map(file => `- ${file.file_path}`).join('\n')
}}

# 실제 변경사항:
{{ 
  $json.changes.map(file => {
    return `## ${file.file_path}\n\n\`\`\`\n${file.diff}\n\`\`\`\n\n`;
  }).join('')
}}

parameters.jsCode:
// Code 노드: 바이너리 및 미디어 파일 필터링 추가
const changes = $input.item.json.changes || [];
let processedChanges = [];

// 코드 리뷰가 불필요한 파일 확장자 목록
const skipExtensions = [
  // 이미지 파일
  '.jpg', '.jpeg', '.png', '.gif', '.svg', '.ico', '.webp', '.bmp', '.tiff',
  // 오디오 파일
  '.mp3', '.wav', '.ogg', '.flac', '.aac', '.m4a',
  // 비디오 파일
  '.mp4', '.webm', '.avi', '.mov', '.mkv', '.flv',
  // 문서 및 기타 바이너리 파일
  '.pdf', '.doc', '.docx', '.xls', '.xlsx', '.ppt', '.pptx',
  // 압축 파일
  '.zip', '.rar', '.tar', '.gz', '.7z',
  // 기타 바이너리 파일
  '.bin', '.exe', '.dll', '.so', '.dylib',
  // 폰트 파일
  '.ttf', '.otf', '.woff', '.woff2',
  // 기타 미디어 리소스
  '.psd', '.ai', '.sketch'
];

// 파일 필터링 및 처리 함수
function shouldProcessFile(filePath) {
  const lowerPath = filePath.toLowerCase();
  // 확장자 기반 필터링
  for (const ext of skipExtensions) {
    if (lowerPath.endsWith(ext)) return false;
  }

  // 특정 디렉토리 필터링 (예: assets, public/images 등)
  const skipDirs = ['node_modules/', 'dist/', 'build/'];
  for (const dir of skipDirs) {
    if (lowerPath.includes(dir)) return false;
  }

  return true;
}

// 바이너리 파일 감지 보조 함수 (diff 내용으로 판단)
function isBinaryContent(diff) {
  // 바이너리 파일의 diff는 종종 "Binary files ... differ" 같은 메시지를 포함함
  if (diff.includes('Binary files') && diff.includes('differ')) return true;

  // NULL 바이트 감지 (바이너리 파일 표시)
  if (diff.includes('\0')) return true;

  // Base64 인코딩된 내용이 지배적인지 확인 (이미지 데이터 등)
  const base64Pattern = /^[A-Za-z0-9+/=]{20,}$/m;
  const lines = diff.split('\n');
  let base64Lines = 0;

  for (let i = 0; i < Math.min(lines.length, 10); i++) {
    if (base64Pattern.test(lines[i])) base64Lines++;
  }

  // 상당수의 라인이 base64로 인코딩된 것으로 보이면 바이너리로 취급
  return base64Lines > 5;
}

// 파일 변경 유형 판단 함수 추가
function getChangeType(change) {
  const {new_path, old_path, diff} = change;

  // 파일 삭제 감지
  if (new_path === '/dev/null' || diff.startsWith('deleted file mode')) {
    return 'delete';
  }

  // 파일명 변경만 있는 경우 감지
  if (old_path !== new_path && old_path !== '/dev/null') {
    // diff 내용 검사
    const actualDiffLines = diff.split('\n')
      .filter(line => line.startsWith('+') || line.startsWith('-'))
      .filter(line => !line.startsWith('+++') && !line.startsWith('---'));

    // 실제 내용 변경이 없으면 rename으로 판단
    if (actualDiffLines.length === 0) {
      return 'rename';
    }

    // 이름 변경과 함께 내용 변경이 있는 경우
    return 'rename+modify';
  }

  // 새 파일 추가
  if (old_path === '/dev/null' || diff.startsWith('new file mode')) {
    return 'add';
  }

  // 기본은 수정으로 간주
  return 'modify';
}

// 변경사항 필터링 및 처리
for (const change of changes) {
  const {old_path, new_path, diff} = change;
  const changeType = getChangeType(change);

  // 리뷰가 필요한 변경 유형 필터링
  // 'add'와 'modify', 'rename+modify'만 처리하고 'rename'과 'delete'는 제외
  if ((changeType === 'add' || changeType === 'modify' || changeType === 'rename+modify') &&
      shouldProcessFile(new_path) && 
      !isBinaryContent(diff)) {

    // 큰 파일 요약 (이전 코드와 동일)
    const isTooLarge = diff.length > 10000;
    const processedDiff = isTooLarge 
      ? `${diff.substring(0, 5000)}... (내용 생략) ...${diff.substring(diff.length - 5000)}` 
      : diff;

    processedChanges.push({
      file_path: new_path,
      old_path: old_path !== new_path ? old_path : null,
      change_type: changeType,
      is_summarized: isTooLarge,
      diff: processedDiff
    });
  }
}

// 변경 유형별 카운트 추가 (선택사항, 로깅용)
const typeCounts = {
  add: changes.filter(c => getChangeType(c) === 'add').length,
  modify: changes.filter(c => getChangeType(c) === 'modify').length,
  delete: changes.filter(c => getChangeType(c) === 'delete').length,
  rename: changes.filter(c => getChangeType(c) === 'rename').length,
  'rename+modify': changes.filter(c => getChangeType(c) === 'rename+modify').length
};

// MR 기본 정보
const mrInfo = {
  // 기존 정보와 동일
  changes: processedChanges,
  // 디버깅/로깅용 정보
  change_type_counts: typeCounts
};

return {json: mrInfo};
